#include <stdio.h>

/*
 * 4-to-2 Priority Encoder Implementation
 * Demonstrates the actual Boolean logic used in hardware
 * 
 * Priority: I3 > I2 > I1 > I0
 * 
 * Boolean Expressions (from truth table):
 * Y1 = I2 + I3
 * Y0 = I1*(!I2)*(!I3) + I3
 * V = I0 + I1 + I2 + I3
 */

typedef struct {
 int Y1; // MSB of output
 int Y0; // LSB of output
 int V; // Valid bit
} EncoderOutput;

// Using direct Boolean expressions (like hardware gates)
EncoderOutput priority_encoder_boolean(int I3, int I2, int I1, int I0) {
 EncoderOutput result;

 // Y1 = I2 + I3 (OR gate)
 result.Y1 = I2 || I3;

 // Y0 = I1*I2'*I3' + I3 (complex logic)
 // This ensures: if I3=1, Y0=1 (output 3)
 // if I2=1 and I3=0, Y0 depends on I1
 int term1 = I1 && (!I2) && (!I3); // I1 AND NOT I2 AND NOT I3
 int term2 = I3; // I3 has highest priority
 result.Y0 = term1 || term2;

 // V = I0 + I1 + I2 + I3 (OR gate - valid bit)
 result.V = I0 || I1 || I2 || I3;

 return result;
}

// Using conditional logic (easier to understand)
EncoderOutput priority_encoder_if(int I3, int I2, int I1, int I0) {
 EncoderOutput result;

 result.V = I3 || I2 || I1 || I0;

 if (I3) {
 result.Y1 = 1; result.Y0 = 1; // 3
 } else if (I2) {
 result.Y1 = 1; result.Y0 = 0; // 2
 } else if (I1) {
 result.Y1 = 0; result.Y0 = 1; // 1
 } else {
 result.Y1 = 0; result.Y0 = 0; // 0 (only if I0=1, else V=0)
 }

 return result;
}

// Simple encoder (problematic with multiple inputs)
void simple_encoder(int I3, int I2, int I1, int I0) {
 // Y1 = I2 + I3 (OR gate)
 int Y1 = I2 || I3;

 // Y0 = I1 + I3 (OR gate)
 int Y0 = I1 || I3;

 printf("Simple Encoder: Y1=%d Y0=%d (INCORRECT if multiple inputs!)\n", Y1, Y0);
}

void print_result(EncoderOutput r, const char* method) {
 printf(" %s: Y1=%d Y0=%d V=%d\n", method, r.Y1, r.Y0, r.V);
}

int main() {
 printf("========================================\n");
 printf("4-to-2 Priority Encoder Demo\n");
 printf("========================================\n\n");

 // Test case array: {I3, I2, I1, I0, description}
 int tests[][5] = {
 {0, 0, 0, 0, 0}, // No input
 {0, 0, 0, 1, 1}, // Only I0
 {0, 0, 1, 0, 2}, // Only I1
 {0, 0, 1, 1, 3}, // I0, I1 - priority to I1
 {0, 1, 0, 0, 4}, // Only I2
 {0, 1, 1, 0, 5}, // I1, I2 - priority to I2
 {1, 0, 0, 0, 6}, // Only I3 (highest)
 {1, 1, 1, 1, 7}, // All inputs - priority to I3
 };

 const char* desc[] = {
 "No input active",
 "Input 0 only (lowest priority)",
 "Input 1 only",
 "Inputs 0 & 1 - priority to 1",
 "Input 2 only",
 "Inputs 1 & 2 - priority to 2",
 "Input 3 only (highest priority)",
 "All inputs active - priority to 3"
 };

 for (int i = 0; i < 8; i++) {
 int I3 = tests[i][0];
 int I2 = tests[i][1];
 int I1 = tests[i][2];
 int I0 = tests[i][3];

 printf("Test %d: %s\n", i+1, desc[i]);
 printf(" Inputs: I3=%d I2=%d I1=%d I0=%d\n", I3, I2, I1, I0);

 EncoderOutput r1 = priority_encoder_boolean(I3, I2, I1, I0);
 EncoderOutput r2 = priority_encoder_if(I3, I2, I1, I0);

 print_result(r1, "Boolean logic");
 print_result(r2, "If-else logic");

 if (I3 + I2 + I1 + I0 > 1) {
 printf(" Note: Multiple inputs handled correctly!\n");
 }
 printf("\n");
 }

 printf("========================================\n");
 printf("Simple Encoder Limitation\n");
 printf("========================================\n");
 printf("\nWhen inputs I3=1 and I2=1 both active:\n");
 simple_encoder(1, 1, 0, 0);
 printf("Priority encoder correctly outputs: Y1=1 Y0=1 (for I3)\n");

 return 0;
}
